 var message: (String) -> Unit = {}
 override fun onError(exception: Exception) {
 exception.message?.let {
 try {
 val json = Json.parseToJsonElement(it).jsonObject
 if (json["message"] != null) {
 message(json["message"].toString().replace("\"", ""))
 return
 }
 } catch (e: Exception) {
 message(it)
